// ============================================
// <<<< API KEY خودت رو فقط اینجا عوض کن >>>>
const API_KEY = 'API_KEY_INJA';
// ============================================

const WORKER_URL = 'https://sweet-meadow-8623.sfarnam73.workers.dev';

const topics = [
  { topic: 'طلاق توافقی چیست و چه مراحلی دارد؟ بررسی کامل شرایط و مدارک', keyword: 'طلاق توافقی', word_count: 2000 },
  { topic: 'مهریه چیست؟ انواع مهریه و نحوه مطالبه مهریه از طریق دادگاه', keyword: 'مطالبه مهریه', word_count: 2000 },
  { topic: 'حضانت فرزند بعد از طلاق: حق حضانت مادر و پدر و سن حضانت', keyword: 'حضانت فرزند', word_count: 1800 },
  { topic: 'نفقه زن: میزان نفقه و شرایط مطالبه نفقه و ضمانت اجرا', keyword: 'نفقه زن', word_count: 1500 },
  { topic: 'نحوه طرح شکایت کیفری: مراحل شکایت در دادسرا و مدارک لازم', keyword: 'شکایت کیفری', word_count: 1800 },
  { topic: 'جرم کلاهبرداری در قانون ایران: تعریف و مصادیق و مجازات', keyword: 'کلاهبرداری', word_count: 2000 },
  { topic: 'خیانت در امانت: تعریف حقوقی و تفاوت با سرقت و مجازات', keyword: 'خیانت در امانت', word_count: 1500 },
  { topic: 'دعاوی ملکی: خلع ید و تصرف عدوانی و الزام به تنظیم سند', keyword: 'دعاوی ملکی', word_count: 2200 },
  { topic: 'قرارداد اجاره: حقوق موجر و مستاجر و فسخ اجاره', keyword: 'حقوق مستاجر', word_count: 1800 },
  { topic: 'چک برگشتی: نحوه شکایت و مجازات صادرکننده چک بلامحل', keyword: 'چک برگشتی', word_count: 2000 },
  { topic: 'وصول مطالبات: روش‌های حقوقی وصول طلب و توقیف اموال', keyword: 'وصول مطالبات', word_count: 1500 },
  { topic: 'قانون ارث در ایران: سهم‌الارث و نحوه تقسیم ارث', keyword: 'تقسیم ارث', word_count: 2200 },
  { topic: 'حقوق کارگر و کارفرما: قرارداد کار و اخراج و سنوات', keyword: 'حقوق کارگر', word_count: 1800 },
  { topic: 'دیه چیست؟ نحوه محاسبه دیه و نرخ دیه و انواع دیه', keyword: 'محاسبه دیه', word_count: 1500 },
  { topic: 'چرا به وکیل نیاز دارید؟ مزایای وکیل پایه یک دادگستری', keyword: 'وکیل پایه یک دادگستری همدان', word_count: 1500 }
];

// انتخاب موضوع بعدی
const counter = $getWorkflowStaticData('global');
let index = counter.topicIndex || 0;
if (index >= topics.length) index = 0;
const pick = topics[index];
counter.topicIndex = index + 1;

// ساخت پرامپت
const prompt = 'تو یک وکیل پایه یک دادگستری و متخصص تولید محتوای حقوقی سئو شده هستی. برای سایت دفتر وکالت چراغی در همدان مقاله بنویس.' +
  '\n\nموضوع: ' + pick.topic +
  '\nکلمه کلیدی اصلی: ' + pick.keyword +
  '\nتعداد کلمات: حداقل ' + pick.word_count + ' کلمه' +
  '\n\n=== قوانین نگارش ===' +
  '\n۱. مقاله باید جامع و دقیق و مبتنی بر قوانین جمهوری اسلامی ایران باشد.' +
  '\n۲. هر جا مرتبط است به شماره مواد قانونی اشاره کن.' +
  '\n۳. از مثال‌های عملی و واقعی استفاده کن.' +
  '\n۴. لحن مقاله حرفه‌ای ولی ساده و قابل فهم برای عموم مردم باشد.' +
  '\n۵. در پایان مقاله بنویس: برای مشاوره حقوقی تخصصی در همدان با دفتر وکالت چراغی تماس بگیرید.' +
  '\n\n=== قوانین سئو ===' +
  '\n۱. کلمه کلیدی اصلی باید در عنوان و جمله اول مقدمه و حداقل ۲ زیرعنوان و متا دیسکریپشن بیاید.' +
  '\n۲. کلمه کلیدی را ۴ تا ۶ بار طبیعی در متن استفاده کن.' +
  '\n۳. عنوان حداکثر ۶۰ کاراکتر و جذاب باشد.' +
  '\n۴. متا دیسکریپشن دقیقاً ۱۵۰ کاراکتر باشد.' +
  '\n\n=== ساختار مقاله ===' +
  '\n- مقدمه: ۲ تا ۳ پاراگراف' +
  '\n- حداقل ۴ بخش با زیرعنوان h2' +
  '\n- هر بخش حداقل ۲ پاراگراف کامل' +
  '\n- از h3 و ul و li و strong استفاده کن' +
  '\n- بخش سوالات متداول: ۴ سوال و جواب' +
  '\n- نتیجه‌گیری' +
  '\n\n=== فرمت خروجی ===' +
  '\nحتماً با این جداکننده‌ها بنویس:' +
  '\n===TITLE===' +
  '\n(عنوان مقاله)' +
  '\n===CONTENT===' +
  '\n(متن کامل مقاله با تگ‌های HTML)' +
  '\n===KEYWORD===' +
  '\n(فقط کلمه کلیدی اصلی)' +
  '\n===META===' +
  '\n(متا دیسکریپشن ۱۵۰ کاراکتری)' +
  '\n\nهیچ بخشی را خالی نگذار.';

// ارسال به Cloudflare Worker
const response = await fetch(WORKER_URL, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    api_key: API_KEY,
    model: 'claude-sonnet-4-6',
    max_tokens: 8000,
    messages: [{ role: 'user', content: prompt }]
  })
});

const data = await response.json();

if (data.error) {
  throw new Error('خطای Claude: ' + (data.error.message || JSON.stringify(data.error)));
}

// پارس کردن پاسخ
let raw = '';
if (data.content && Array.isArray(data.content)) {
  raw = data.content[0].text;
} else if (data.text) {
  raw = data.text;
} else {
  throw new Error('پاسخ نامعتبر از Claude');
}

function getPart(label, next) {
  let start = raw.indexOf('===' + label + '===');
  if (start === -1) return '';
  start = start + ('===' + label + '===').length;
  let end = next ? raw.indexOf('===' + next + '===') : raw.length;
  if (end === -1) end = raw.length;
  return raw.substring(start, end).trim();
}

let title = getPart('TITLE', 'CONTENT');
let content = getPart('CONTENT', 'KEYWORD');
let keyword = getPart('KEYWORD', 'META');
let meta = getPart('META', null);

if (!title) title = pick.topic;
if (!keyword) keyword = pick.keyword;
if (!meta) meta = title;
if (!content) throw new Error('مقاله تولید نشد');

return [{
  json: {
    title: title,
    content: content,
    focus_keyword: keyword,
    meta_description: meta
  }
}];
